### Backend (Node.js + Express + MongoDB)

First, let's set up our backend. We'll use Express to handle API requests and connect to MongoDB.

1. **Initialize the project:**
   ```bash
   mkdir room-management
   cd room-management
   npm init -y
   ```

2. **Install dependencies:**
   ```bash
   npm install express mongoose cors body-parser
   ```

3. **Create the server file (`server.js`):**
   ```javascript
   const express = require('express');
   const mongoose = require('mongoose');
   const cors = require('cors');
   const bodyParser = require('body-parser');

   const app = express();
   const PORT = process.env.PORT || 5000;

   // Middleware
   app.use(cors());
   app.use(bodyParser.json());

   // Connect to MongoDB
   mongoose.connect('mongodb://localhost:27017/roomManagement', {
     useNewUrlParser: true,
     useUnifiedTopology: true
   });

   // Room Schema
   const RoomSchema = new mongoose.Schema({
     name: String,
     capacity: Number,
     isAvailable: Boolean
   });

   const Room = mongoose.model('Room', RoomSchema);

   // Routes
   app.get('/api/rooms', async (req, res) => {
     const rooms = await Room.find({});
     res.send(rooms);
   });

   app.post('/api/rooms', async (req, res) => {
     const room = new Room(req.body);
     await room.save();
     res.status(201).send(room);
   });

   app.delete('/api/rooms/:id', async (req, res) => {
     const deletedRoom = await Room.findByIdAndDelete(req.params.id);
     if (!deletedRoom) return res.status(404).send('No room found');
     res.send(deletedRoom);
   });

   // Start the server
   app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
   ```

